module top_module(
    input [3:0] in,
    output [3:0] out
);// Module supplies
    supply1 VPWR;
    supply0 VGND;

    // Local signals
    wire [3:0] temp;
    wire [3:0] obf_shifted;

    // Assign the input to temp
    assign temp = in;

    // Shift the bits in temp to the left by one position and assign the result to obf_shifted
    assign obf_shifted = {temp[2:0], temp[3]};

    // Assign obf_shifted to the output
    assign out = obf_shifted;

endmodule
